import React from 'react';
import './Stock.css'

function DisplayStockData({ stockData }) {
  // if (!stockData) {
  //   return <p>ENTER STOCK</p>;
  // }
  const arrow = stockData.change > 0 ? '\u25B2' : '\u25BC';
  const mp = stockData.change > 0 ? '\x2b' : '\u2212';
  const isStockUp = stockData.change > 0;
  const Change = Math.abs(stockData.change);


  return (
    <div className='con'>
    <div className='info'>
      <div>
        <p style={{color: isStockUp ? "orange" : "red"}}>{stockData.symbol}</p>
        <p style={{color: isStockUp ? "orange" : "red"}}>{stockData.price}</p>
      </div>
      <div>
        <p style={{color: isStockUp ? "orange" : "red"}}>{arrow}{stockData.pChange}</p>
        <p style={{color: isStockUp ? "orange" : "red"}}>&thinsp;{mp}&thinsp;{Change}</p>
      </div>
    </div>
    </div>

  );
}

export default DisplayStockData;
